def retrieve(self, prompt: str):
    matches = self.scanner.search(prompt)

    documents = []
    seen = set()

    for match in matches:
        if match.path in seen:
            continue

        seen.add(match.path)

        try:
            chunks = self.search.retrieve_chunks(match, prompt)
            if chunks:
                for chunk in chunks:
                    if self._chunk_key(chunk, match.path) in seen:
                        continue
                    seen.add(self._chunk_key(chunk, match.path))
                    documents.append(
                        {
                            "path": match.path,
                            "symbol": chunk.name,
                            "chunk_type": chunk.kind,
                            "start_line": chunk.start_line,
                            "end_line": chunk.end_line,
                            "content": self._trim_chunk(chunk.content),
                            "score": self._score_chunk(chunk, match),
                        }
                    )
            else:
                content = self.files.read(match.path)
                if len(content) > self.MAX_FILE_SIZE:
                    content = content[: self.MAX_FILE_SIZE] + "\n\n... FILE TRUNCATED ..."

                documents.append(
                    {
                        "path": match.path,
                        "symbol": None,
                        "chunk_type": "file",
                        "start_line": 1,
                        "end_line": None,
                        "content": content,
                        "score": self._score_file(match),
                    }
                )
        except Exception:
            continue

    documents.sort(key=lambda item: item["score"], reverse=True)
    return self._apply_token_budget(documents[: self.MAX_DOCUMENTS])

def _score_file(self, indexed_file) -> int:
    return (
        len(indexed_file.functions) * 3
        + len(indexed_file.classes) * 3
        + len(indexed_file.imports)
    )

def _apply_token_budget(self, documents: list[dict]) -> list[dict]:
    budgeted = []
    used = 0
    for document in documents:
        estimated_tokens = max(1, len(document["content"].split()))
        if used + estimated_tokens > self.MAX_CONTEXT_TOKENS:
            break
        budgeted.append(document)
        used += estimated_tokens
    return budgeted

